// ─────────────────────────────────────────────────────
//  PRELOADER
// ─────────────────────────────────────────────────────
const comicCache = new Map<string, HTMLImageElement>();

function loadComic(src: string): Promise<HTMLImageElement> {
  if (!src) return Promise.resolve(new Image());
  const cached = comicCache.get(src);
  if (cached) return Promise.resolve(cached);
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => { comicCache.set(src, img); resolve(img); };
    img.onerror = reject;
    img.src = src;
  });
}

/** Preload de todos os painéis de comic — chamar no boot do app */
export async function preloadComicSprites(): Promise<void> {
  const all = [
    INTRO_P1, INTRO_P2, INTRO_P3, INTRO_P4,
    TRANS1_P1, TRANS1_P2, TRANS1_P3, TRANS1_P4,
    TRANS2_P1, TRANS2_P2, TRANS2_P3, TRANS2_P4,
    TRANS3_P1, TRANS3_P2, TRANS3_P3, TRANS3_P4,
    TRANS4_P1, TRANS4_P2, TRANS4_P3, TRANS4_P4,
  ].filter(s => s.length > 0);
  await Promise.all(all.map(loadComic));
}
